import{_ as e,o as i,c as a,a2 as o}from"./chunks/framework.C58al07P.js";const m=JSON.parse('{"title":"Expiration des emails","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/expiration.md","filePath":"fr/guide/expiration.md"}'),r={name:"fr/guide/expiration.md"};function n(s,t,d,l,u,c){return i(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="expiration-des-emails" tabindex="-1">Expiration des emails <a class="header-anchor" href="#expiration-des-emails" aria-label="Permalink to &quot;Expiration des emails&quot;">​</a></h1><p>La fonctionnalité d&#39;expiration permet de marquer certains emails comme <strong>temporaires</strong> pour qu&#39;ils soient automatiquement supprimés après une durée définie. C&#39;est particulièrement utile pour les emails qui n&#39;ont plus de valeur après un certain temps.</p><h2 id="types-d-emails-temporaires" tabindex="-1">Types d&#39;emails temporaires <a class="header-anchor" href="#types-d-emails-temporaires" aria-label="Permalink to &quot;Types d&#39;emails temporaires&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Catégorie</th><th>Description</th><th style="text-align:center;">Durée par défaut</th></tr></thead><tbody><tr><td><strong>Code OTP</strong></td><td>Codes de vérification, 2FA, connexion</td><td style="text-align:center;">1 jour</td></tr><tr><td><strong>Livraison</strong></td><td>Suivi de colis, confirmations d&#39;expédition</td><td style="text-align:center;">14 jours</td></tr><tr><td><strong>Promotion</strong></td><td>Offres flash, codes promo, soldes</td><td style="text-align:center;">7 jours</td></tr><tr><td><strong>Manuel</strong></td><td>Tout email marqué manuellement</td><td style="text-align:center;">7 jours</td></tr></tbody></table><h2 id="detection-automatique" tabindex="-1">Détection automatique <a class="header-anchor" href="#detection-automatique" aria-label="Permalink to &quot;Détection automatique&quot;">​</a></h2><p>Cliquez sur <strong>Détecter automatiquement</strong> pour scanner vos emails récents. L&#39;application analyse le sujet et l&#39;expéditeur de chaque email pour identifier les emails temporaires via des heuristiques :</p><ul><li><strong>Codes OTP</strong> : détection par mots-clés (verification, code, OTP, sign-in, security) et expéditeurs (noreply, security)</li><li><strong>Livraisons</strong> : détection par mots-clés (shipping, tracking, colis, commande) et transporteurs connus (UPS, FedEx, DHL, Colissimo)</li><li><strong>Promotions</strong> : détection par mots-clés (promo, sale, discount, offre) et expéditeurs marketing</li></ul><p>Après la détection, vous pouvez sélectionner les emails à marquer comme temporaires et ajuster la durée si nécessaire.</p><h2 id="ajout-manuel" tabindex="-1">Ajout manuel <a class="header-anchor" href="#ajout-manuel" aria-label="Permalink to &quot;Ajout manuel&quot;">​</a></h2><p>Vous pouvez aussi ajouter manuellement un email à la liste d&#39;expiration :</p><ol><li>Cliquez sur <strong>Ajouter manuellement</strong></li><li>Saisissez l&#39;ID du message Gmail</li><li>Choisissez la catégorie</li><li>Définissez le nombre de jours avant expiration</li></ol><h2 id="tableau-de-bord" tabindex="-1">Tableau de bord <a class="header-anchor" href="#tableau-de-bord" aria-label="Permalink to &quot;Tableau de bord&quot;">​</a></h2><p>La page affiche 4 statistiques :</p><ul><li><strong>En attente</strong> : emails marqués qui n&#39;ont pas encore expiré</li><li><strong>Expire bientôt</strong> : emails qui expirent dans les 24 prochaines heures</li><li><strong>Supprimés</strong> : emails déjà supprimés automatiquement</li><li><strong>Total</strong> : nombre total d&#39;expirations créées</li></ul><h2 id="fonctionnement" tabindex="-1">Fonctionnement <a class="header-anchor" href="#fonctionnement" aria-label="Permalink to &quot;Fonctionnement&quot;">​</a></h2><p>Le système vérifie les expirations <strong>toutes les 15 minutes</strong>. Quand un email atteint sa date d&#39;expiration, il est automatiquement envoyé dans la corbeille Gmail (pas de suppression définitive, ce qui laisse 30 jours pour récupérer).</p><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Méthode</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/expiration/:accountId</code></td><td>Lister les expirations</td></tr><tr><td><code>GET</code></td><td><code>/api/expiration/:accountId/stats</code></td><td>Statistiques</td></tr><tr><td><code>POST</code></td><td><code>/api/expiration/:accountId</code></td><td>Créer une expiration</td></tr><tr><td><code>POST</code></td><td><code>/api/expiration/:accountId/batch</code></td><td>Créer en lot</td></tr><tr><td><code>POST</code></td><td><code>/api/expiration/:accountId/detect</code></td><td>Détection heuristique</td></tr><tr><td><code>PATCH</code></td><td><code>/api/expiration/:accountId/:id</code></td><td>Modifier la date</td></tr><tr><td><code>DELETE</code></td><td><code>/api/expiration/:accountId/:id</code></td><td>Supprimer l&#39;expiration</td></tr></tbody></table>',18)])])}const h=e(r,[["render",n]]);export{m as __pageData,h as default};
